	if flags.APIURL == "" && (orgConfig == nil || orgConfig.APIURL == "") {
		form := huh.NewForm(
			huh.NewGroup(
				huh.NewSelect[string]().
					Title("Choose your region").
					Options(
						huh.NewOption("Europe", "eu"),
						huh.NewOption("US", "us"),
